mapper.select:
SELECT p.PLAYER_SEQ as playerSeq, p.PLAYER_NAME as playerName, p.RACE as race, p.RARITY as rarity, p.STAT_ATTACK as statAttack, p.STAT_DEFENSE as statDefense, p.STAT_HP as statHp, p.STAT_HARASS as statHarass, p.STAT_SPEED as statSpeed, p.PLAYER_IMG_URL as playerImgUrl, p.PLAYER_COST as playerCost, opp.SET_NUMBER as setNumber, opp.BUILD_ID_VS_T as buildIdVsT, opp.BUILD_ID_VS_Z as buildIdVsZ, opp.BUILD_ID_VS_P as buildIdVsP FROM TBL_PVE_OPPONENTS opp JOIN TBL_PLAYERS p ON opp.PLAYER_SEQ = p.PLAYER_SEQ WHERE opp.STAGE_LEVEL = #{stageLevel} AND opp.SUB_LEVEL = #{subLevel}
AND opp.SET_NUMBER BETWEEN #{setStart} AND #{setEnd}
AND opp.SET_NUMBER = #{setNumber}
ORDER BY opp.SET_NUMBER ASC, opp.OPPONENT_ID ASC
